"use client";

import { Globe, Menu, Search, ShoppingBag, UserCircle2, X } from "lucide-react";
import Link from "next/link";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { useMemo, useState } from "react";

import { useStorefront } from "@/components/providers/StorefrontProvider";
import { useSupabaseSession } from "@/components/providers/SupabaseSessionProvider";
import { cn } from "@/lib/utils";
import { useCartStore } from "@/store/cart";

const NAV_ITEMS = [
  { href: "/", key: "nav.home" },
  { href: "/products", key: "nav.products" },
  { href: "/cart", key: "nav.cart" },
];

export function Header() {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const totalItems = useCartStore((state) => state.totalItems);
  const { user } = useSupabaseSession();
  const { isRTL, t, toggleLanguage } = useStorefront();

  const accountHref = user ? "/account" : "/auth/login";
  const accountLabel = user ? t("nav.account") : t("nav.login");

  const mobileNavItems = useMemo(
    () => [...NAV_ITEMS, { href: accountHref, key: user ? "nav.account" : "nav.login" }],
    [accountHref, user]
  );

  const handleSearchSubmit = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const formData = new FormData(event.currentTarget);
    const nextQuery = String(formData.get("q") ?? "").trim();

    if (!nextQuery) {
      router.push("/products");
      setIsMenuOpen(false);
      return;
    }

    router.push(`/products?q=${encodeURIComponent(nextQuery)}`);
    setIsMenuOpen(false);
  };

  const handleToggleLanguage = () => {
    toggleLanguage();
    router.refresh();
  };

  return (
    <header className="sticky top-0 z-40 border-b border-white/60 bg-[#f7fbf7]/90 backdrop-blur-xl">
      <div className="mx-auto flex w-full max-w-7xl flex-col gap-4 px-4 py-4 sm:px-6 lg:px-8">
        <div
          className={cn(
            "flex items-center justify-between gap-3",
            isRTL && "sm:flex-row-reverse"
          )}
        >
          <div className="flex items-center gap-3">
            <button
              type="button"
              className="inline-flex h-11 w-11 items-center justify-center rounded-2xl border border-emerald-100 bg-white text-slate-700 shadow-sm transition hover:border-primary hover:text-primary lg:hidden"
              onClick={() => setIsMenuOpen((current) => !current)}
              aria-label={t("nav.menu")}
            >
              {isMenuOpen ? <X size={20} /> : <Menu size={20} />}
            </button>

            <Link
              href="/"
              className={cn(
                "group inline-flex items-center gap-3 rounded-3xl border border-emerald-100 bg-white/90 px-4 py-3 shadow-soft transition hover:-translate-y-0.5 hover:border-primary/30",
                isRTL && "sm:flex-row-reverse"
              )}
            >
              <span className="flex h-11 w-11 items-center justify-center rounded-2xl bg-primary text-lg font-bold text-white">
                أ
              </span>
              <span className="flex flex-col leading-tight">
                <span className="text-xs font-medium uppercase tracking-[0.28em] text-primary/70">
                  Al-Amal Center
                </span>
                <span className="font-ibm text-base font-semibold text-slate-900">
                  الأمل سنتر
                </span>
              </span>
            </Link>
          </div>

          <div className="hidden items-center gap-2 lg:flex">
            {NAV_ITEMS.map((item) => (
              <Link
                key={item.href}
                href={item.href}
                className={cn(
                  "rounded-full px-4 py-2 text-sm font-medium transition",
                  pathname === item.href
                    ? "bg-primary text-white shadow-sm"
                    : "text-slate-600 hover:bg-white hover:text-primary"
                )}
              >
                {t(item.key)}
              </Link>
            ))}
          </div>

          <div className="flex items-center gap-2">
            <button
              type="button"
              onClick={handleToggleLanguage}
              className="inline-flex h-11 items-center gap-2 rounded-2xl border border-emerald-100 bg-white px-4 text-sm font-medium text-slate-700 shadow-sm transition hover:border-primary hover:text-primary"
            >
              <Globe size={17} />
              <span>{t("nav.language")}</span>
            </button>

            <Link
              href="/cart"
              className="relative inline-flex h-11 w-11 items-center justify-center rounded-2xl border border-emerald-100 bg-white text-slate-700 shadow-sm transition hover:border-primary hover:text-primary"
              aria-label={t("nav.cart")}
            >
              <ShoppingBag size={19} />
              <span className="absolute -right-1 -top-1 min-w-5 rounded-full bg-secondary px-1.5 py-0.5 text-center text-[11px] font-bold text-slate-900">
                {totalItems}
              </span>
            </Link>

            <Link
              href={accountHref}
              className="hidden h-11 items-center gap-2 rounded-2xl border border-emerald-100 bg-white px-4 text-sm font-medium text-slate-700 shadow-sm transition hover:border-primary hover:text-primary sm:inline-flex"
            >
              <UserCircle2 size={18} />
              <span>{accountLabel}</span>
            </Link>
          </div>
        </div>

        <div className={cn("flex flex-col gap-3", isMenuOpen ? "block" : "hidden lg:flex")}>
          <form onSubmit={handleSearchSubmit} className="flex items-center gap-3">
            <div className="relative flex-1">
              <Search
                className={cn(
                  "pointer-events-none absolute top-1/2 -translate-y-1/2 text-slate-400",
                  isRTL ? "right-4" : "left-4"
                )}
                size={18}
              />
              <input
                key={`${pathname}-${searchParams.get("q") ?? ""}`}
                name="q"
                defaultValue={searchParams.get("q") ?? ""}
                placeholder={t("nav.search")}
                className={cn(
                  "h-12 w-full rounded-2xl border border-emerald-100 bg-white px-4 text-sm text-slate-900 shadow-sm outline-none ring-0 transition placeholder:text-slate-400 focus:border-primary",
                  isRTL ? "pr-12 text-right" : "pl-12"
                )}
              />
            </div>
            <button
              type="submit"
              className="inline-flex h-12 items-center justify-center rounded-2xl bg-primary px-5 text-sm font-semibold text-white shadow-sm transition hover:bg-[#256a2a]"
            >
              {t("nav.search")}
            </button>
          </form>

          <div className="grid gap-2 lg:hidden">
            {mobileNavItems.map((item) => (
              <Link
                key={item.href}
                href={item.href}
                onClick={() => setIsMenuOpen(false)}
                className={cn(
                  "rounded-2xl border px-4 py-3 text-sm font-medium transition",
                  pathname === item.href
                    ? "border-primary bg-primary text-white"
                    : "border-emerald-100 bg-white text-slate-700 hover:border-primary/40 hover:text-primary"
                )}
              >
                {t(item.key)}
              </Link>
            ))}
          </div>
        </div>
      </div>
    </header>
  );
}
